package com.cho2hand.marketplace.entity.report;import jakarta.persistence.*;import java.time.Instant;
@Entity@Table(name="listing_reports")public class ListingReport{@Id@GeneratedValue(strategy=GenerationType.IDENTITY)@Column(name="listing_report_id")private Long id;@Column(name="listing_id")private Long listingId;@Column(name="reporter_user_id")private Long reporterUserId;@Column(name="report_reason_id")private Long reasonId;private String details;private String status;@Column(name="resolution_note")private String resolutionNote;@Column(name="resolved_at")private Instant resolvedAt;@Column(name="resolved_by_user_id")private Long resolvedByUserId;@Column(name="created_at")private Instant createdAt;@PrePersist void created(){createdAt=Instant.now();status="OPEN";}public Long getId(){return id;}public Long getListingId(){return listingId;}public Long getReporterUserId(){return reporterUserId;}public Long getReasonId(){return reasonId;}public String getDetails(){return details;}public String getStatus(){return status;}public String getResolutionNote(){return resolutionNote;}public Instant getResolvedAt(){return resolvedAt;}public Instant getCreatedAt(){return createdAt;}public void setListingId(Long v){listingId=v;}public void setReporterUserId(Long v){reporterUserId=v;}public void setReasonId(Long v){reasonId=v;}public void setDetails(String v){details=v;}public void resolve(String value,String note,Long admin){status=value;resolutionNote=note;resolvedByUserId=admin;resolvedAt=Instant.now();}}
